function getSeedTypeColor(type) {
  return SEED_TYPES[type] || "#999";
}

function getSeedDomainColor(domain) {
  const primary = domain.split(",")[0].trim();
  return SEED_DOMAINS[primary] || "#999";
}

function getSeedLevelSize(level) {
  return (SEED_LEVELS[level] || SEED_LEVELS["heard"]).size;
}

function getSeedLevelColor(level) {
  return (SEED_LEVELS[level] || SEED_LEVELS["heard"]).color;
}
